import{_ as a,o,c as i,ai as t,b5 as r,b6 as l}from"./chunks/framework.Di2lRXru.js";const u=JSON.parse('{"title":"SimpleModManager","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/simplemodmanager.md","filePath":"homebrew/simplemodmanager.md"}'),n={name:"homebrew/simplemodmanager.md"};function d(s,e,m,c,h,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="simplemodmanager" tabindex="-1">SimpleModManager <a class="header-anchor" href="#simplemodmanager" aria-label="Permalink to “SimpleModManager”">​</a></h1><p>SimpleModManager is a <a href="./index#terminologies">homebrew app</a> that allows easily adding and removing mods to the layeredFS directory from another directory on the SD card. More information can be found on the <a href="https://github.com/nadrino/SimpleModManager" target="_blank" rel="noreferrer">SimpleModManager GitHub</a> repository.</p><details class="details custom-block"><summary>Common use cases for SimpleModManager:</summary><ul><li>Switching between large modpacks</li><li>Enabling and disabling individual mods</li></ul></details><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p><strong>What NOT to use SimpleModManager for</strong></p><p>SimpleModManager should not be used for some specific games like Super Smash Bros. Ultimate and The Legend of Zelda: Breath of the Wild and Tears of the Kingdom. This is due to how these games handle mods differently from others.</p></div><h2 id="section-i-requirements" tabindex="-1">Section I - Requirements <a class="header-anchor" href="#section-i-requirements" aria-label="Permalink to “Section I - Requirements”">​</a></h2><ul><li>The latest release of <a href="https://github.com/DefenderOfHyrule/SimpleModManager/releases/tag/v2.1.4" target="_blank" rel="noreferrer">SimpleModManager</a> (the <code>SimpleModManager.nro</code> file)</li></ul><h2 id="section-ii-installation" tabindex="-1">Section II - Installation <a class="header-anchor" href="#section-ii-installation" aria-label="Permalink to “Section II - Installation”">​</a></h2><ol><li>Boot into hekate and go to <code>Tools</code> &gt; <code>USB Tools</code> &gt; <code>SD Card</code>, then plug your Switch into your PC via USB.</li><li>Your microSD card should now be accessible on your PC, open it.</li><li>Copy the <code>SimpleModManager.nro</code> file the <code>/switch/</code> folder on your microSD card.</li><li>Boot into CFW.</li></ol><h2 id="section-iii-usage" tabindex="-1">Section III - Usage <a class="header-anchor" href="#section-iii-usage" aria-label="Permalink to “Section III - Usage”">​</a></h2><ol><li>Create a directory named <code>mods/&lt;game name&gt;/&lt;mod name&gt;/</code> on the root of the microSD card. <ul><li>What you put for the mod name does not have to align with anything, put whatever you like!</li></ul></li><li>Create the layeredFS directory for your mod that can be found on the <a href="./../extras/game_modding">Game Modding</a> page, skipping the <code>atmosphere</code> folder inside the <code>&lt;mod name&gt;</code> folder.</li><li>Launch SimpleModManager via the Homebrew Menu and your games will show up, pressing A on them will show the mods available.</li></ol><p><img src="'+r+'" alt="ExampleSwitchTheme" width="600"><img src="'+l+'" alt="ExampleSwitchTheme" width="600"></p>',11)])])}const f=a(n,[["render",d]]);export{u as __pageData,f as default};
